(4, '**Çıkış saati** öğlen on iki.', 'The **check-out** time is noon.', '**Utcheckningstiden** är mitt på dagen.', 'Die **Abreisezeit** ist mittags um zwölf.', '["çıkış saati"]', '["check-out"]', '["utcheckningstiden"]', '["Abreisezeit"]', 'beginner', false, 92),
(4, 'Oraya gitmek **ne kadar sürer**?', '**How long does it take** to get there?', '**Hur lång tid tar det** att komma dit?', '**Wie lange dauert es**, dorthin zu kommen?', '["ne kadar sürer"]', '["how long does it take"]', '["hur lång tid tar det"]', '["wie lange dauert es"]', 'beginner', false, 93),
