(4, 'Bugün **geri dönmemiz** gerekiyor.', 'We need to **head back** today.', 'Vi måste **bege oss tillbaka** idag.', 'Wir müssen heute **zurückkehren**.', '["geri dönmemiz"]', '["head back"]', '["bege oss tillbaka"]', '["zurückkehren"]', 'advanced', false, 114),
(4, 'Rehber bize şehri **gezdirdi**.', 'The guide **showed us around** the city.', 'Guiden **visade oss runt** i staden.', 'Der Führer hat uns die Stadt **gezeigt**.', '["gezdirdi"]', '["showed us around"]', '["visade oss runt"]', '["gezeigt"]', 'advanced', false, 115),
(4, 'Yarın **gezmeye çıkacağız**.', 'Tomorrow we''re going to **go sightseeing**.', 'Imorgon ska vi **gå på sightseeing**.', 'Morgen werden wir **Sightseeing machen**.', '["gezmeye çıkacağız"]', '["go sightseeing"]', '["gå på sightseeing"]', '["Sightseeing machen"]', 'advanced', false, 116),
(4, 'Otel fiyatına kahvaltı **dahil mi**?', 'Is breakfast **included** in the hotel price?', 'Ingår frukost **i hotellpriset**?', 'Ist das Frühstück **im Hotelpreis inbegriffen**?', '["dahil mi"]', '["included"]', '["i hotellpriset"]', '["inbegriffen"]', 'advanced', false, 117),
(4, 'Zaman kaybetmeden **doğrudan** terminale gidelim.', 'Let''s go **straight to** the terminal without wasting time.', 'Låt oss gå **direkt till** terminalen utan att slösa tid.', 'Lass uns **direkt zum** Terminal gehen ohne Zeit zu verlieren.', '["doğrudan"]', '["straight to"]', '["direkt till"]', '["direkt zum"]', 'advanced', false, 118),
(4, 'Pasaport kontrolünden **geçmemiz** gerekiyor.', 'We need to **go through** passport control.', 'Vi behöver **gå igenom** passkontrollen.', 'Wir müssen durch die Passkontrolle **gehen**.', '["geçmemiz"]', '["go through"]', '["gå igenom"]', '["gehen durch"]', 'advanced', false, 119),
