INSERT INTO sentences (category_id, text_tr, text_en, text_sv, text_de, keywords_tr, keywords_en, keywords_sv, keywords_de, difficulty, is_free, sort_order) VALUES

-- Beginner
(5, 'İklim değişikliğine **ek olarak** hava kirliliği de ciddi bir sorun.', '**In addition to** climate change, air pollution is also a serious problem.', '**Förutom** klimatförändringarna är luftföroreningar också ett allvarligt problem.', '**Zusätzlich zum** Klimawandel ist auch Luftverschmutzung ein ernstes Problem.', '["ek olarak"]', '["in addition to"]', '["förutom"]', '["zusätzlich zum"]', 'beginner', false, 121),
(5, 'Araştırma yetersizdi; **bunun sonucunda** proje başarısız oldu.', 'The research was insufficient; **as a result**, the project failed.', 'Forskningen var otillräcklig; **som ett resultat** misslyckades projektet.', 'Die Forschung war unzureichend; **als Ergebnis** scheiterte das Projekt.', '["bunun sonucunda"]', '["as a result"]', '["som ett resultat"]', '["als Ergebnis"]', 'beginner', false, 122),
(5, 'Bu yaklaşım pratik; **öte yandan** pahalı.', 'This approach is practical; **on the other hand**, it''s expensive.', 'Det här tillvägagångssättet är praktiskt; **å andra sidan** är det dyrt.', 'Dieser Ansatz ist praktisch; **andererseits** ist er teuer.', '["öte yandan"]', '["on the other hand"]', '["å andra sidan"]', '["andererseits"]', 'beginner', false, 123),
(5, '**Sonuç olarak**, bu yöntem daha verimli.', '**In conclusion**, this method is more efficient.', '**Sammanfattningsvis** är den här metoden effektivare.', '**Abschließend** lässt sich sagen, dass diese Methode effizienter ist.', '["sonuç olarak"]', '["in conclusion"]', '["sammanfattningsvis"]', '["abschließend"]', 'beginner', false, 124),
(5, 'Bu hipotez **verilere dayanıyor**.', 'This hypothesis is **based on** the data.', 'Den här hypotesen är **baserad på** datan.', 'Diese Hypothese **basiert auf** den Daten.', '["verilere dayanıyor"]', '["based on"]', '["baserad på"]', '["basiert auf"]', 'beginner', false, 125),
(5, 'Verimlilik **açısından** bu yöntem daha iyi.', '**In terms of** efficiency, this method is better.', '**Vad gäller** effektivitet är den här metoden bättre.', '**Was die Effizienz betrifft**, ist diese Methode besser.', '["açısından"]', '["in terms of"]', '["vad gäller"]', '["was betrifft"]', 'beginner', false, 126),
(5, '**Araştırmaya göre**, uyku sağlığı etkiliyor.', '**According to** the research, sleep affects health.', '**Enligt** forskningen påverkar sömn hälsan.', '**Laut** der Forschung beeinflusst Schlaf die Gesundheit.', '["araştırmaya göre"]', '["according to"]', '["enligt"]', '["laut"]', 'beginner', false, 127),
(5, '**Bir başka deyişle**, stratejiyi değiştirmemiz gerekiyor.', '**In other words**, we need to change our strategy.', '**Med andra ord** behöver vi ändra vår strategi.', '**Mit anderen Worten** müssen wir unsere Strategie ändern.', '["bir başka deyişle"]', '["in other words"]', '["med andra ord"]', '["mit anderen Worten"]', 'beginner', false, 128),
(5, '**Özetle**, bulgular ümit verici.', '**To sum up**, the findings are promising.', '**Sammanfattningsvis** är fynden lovande.', '**Zusammenfassend** sind die Ergebnisse vielversprechend.', '["özetle"]', '["to sum up"]', '["sammanfattningsvis"]', '["zusammenfassend"]', 'beginner', false, 129),
(5, '**Örneğin**, bağışıklık sistemi strese tepki verir.', '**For instance**, the immune system responds to stress.', '**Till exempel** reagerar immunsystemet på stress.', '**Zum Beispiel** reagiert das Immunsystem auf Stress.', '["örneğin"]', '["for instance"]', '["till exempel"]', '["zum Beispiel"]', 'beginner', false, 130),

-- Intermediate
(5, 'Bu veri sence **mantıklı mı**?', 'Does this data **make sense** to you?', 'Är det här datat **vettigt** för dig?', 'Ergibt dieses Datum für dich **Sinn**?', '["mantıklı mı"]', '["make sense"]', '["vettigt"]', '["Sinn ergeben"]', 'intermediate', false, 131),
(5, '**Bildiğim kadarıyla**, bu yöntem henüz test edilmedi.', '**As far as I know**, this method hasn''t been tested yet.', '**Vad jag vet** har den här metoden inte testats ännu.', '**Soweit ich weiß** wurde diese Methode noch nicht getestet.', '["bildiğim kadarıyla"]', '["as far as I know"]', '["vad jag vet"]', '["soweit ich weiß"]', 'intermediate', false, 132),
(5, 'Yazar birkaç kritik sorunu **dile getiriyor**.', 'The author **points out** several critical issues.', 'Författaren **påpekar** flera kritiska problem.', 'Der Autor **weist auf** mehrere kritische Probleme **hin**.', '["dile getiriyor"]', '["points out"]', '["påpekar"]', '["weist hin"]', 'intermediate', false, 133),
(5, 'Bu makale önceki çalışmalara **atıfta bulunuyor**.', 'This article **refers to** previous studies.', 'Den här artikeln **hänvisar till** tidigare studier.', 'Dieser Artikel **bezieht sich auf** frühere Studien.', '["atıfta bulunuyor"]', '["refers to"]', '["hänvisar till"]', '["bezieht sich auf"]', 'intermediate', false, 134),
(5, 'Karar verirken bağlamı **dikkate almamız** lazım.', 'We must **take into account** the context when deciding.', 'Vi måste **ta hänsyn till** sammanhanget när vi beslutar.', 'Wir müssen den Kontext **berücksichtigen** wenn wir entscheiden.', '["dikkate almamız"]', '["take into account"]', '["ta hänsyn till"]', '["berücksichtigen"]', 'intermediate', false, 135),
(5, 'Uzun vadeli çözümler **yerine** kısa vadeli önlemler alındı.', 'Short-term measures were taken **rather than** long-term solutions.', 'Kortsiktiga åtgärder vidtogs **snarare än** långsiktiga lösningar.', 'Kurzfristige Maßnahmen wurden **anstatt** langfristiger Lösungen ergriffen.', '["yerine"]', '["rather than"]', '["snarare än"]', '["anstatt"]', 'intermediate', false, 136),
(5, 'Sonuç **ne olursa olsun**, araştırmaya devam ettik.', '**Regardless of** the result, we continued our research.', '**Oavsett** resultatet fortsatte vi vår forskning.', '**Ungeachtet** des Ergebnisses setzten wir unsere Forschung fort.', '["ne olursa olsun"]', '["regardless of"]', '["oavsett"]', '["ungeachtet"]', 'intermediate', false, 137),
(5, 'Koşullar sağlandığı **sürece** deney geçerli.', 'The experiment is valid **provided that** conditions are met.', 'Experimentet är giltigt **förutsatt att** villkoren uppfylls.', 'Das Experiment ist gültig, **vorausgesetzt** die Bedingungen sind erfüllt.', '["sürece"]', '["provided that"]', '["förutsatt att"]', '["vorausgesetzt"]', 'intermediate', false, 138),
(5, 'Bu bulgu konuya **ışık tutuyor**.', 'This finding **sheds light on** the issue.', 'Det här fyndet **kastar ljus på** problemet.', 'Dieser Befund **beleuchtet** das Thema.', '["ışık tutuyor"]', '["sheds light on"]', '["kastar ljus på"]', '["beleuchtet"]', 'intermediate', false, 139),
(5, '**Belirtmek gerekir ki**, yöntemler tartışmalı.', '**It is worth noting** that the methods are debatable.', 'Det är **värt att notera** att metoderna är diskutabla.', 'Es ist **erwähnenswert**, dass die Methoden umstritten sind.', '["belirtmek gerekir ki"]', '["it is worth noting"]', '["värt att notera"]', '["erwähnenswert"]', 'intermediate', false, 140),

-- Advanced
(5, 'Bu çalışma etik **bağlamında** inceleniyor.', 'This study is examined **with regard to** ethics.', 'Den här studien granskas **med avseende på** etik.', 'Diese Studie wird **hinsichtlich** der Ethik untersucht.', '["bağlamında"]', '["with regard to"]', '["med avseende på"]', '["hinsichtlich"]', 'advanced', false, 141),
(5, 'Çalışma, mevcut boşluklara **dikkat çekiyor**.', 'The study **draws attention to** existing gaps.', 'Studien **uppmärksammar** befintliga luckor.', 'Die Studie **lenkt die Aufmerksamkeit** auf bestehende Lücken.', '["dikkat çekiyor"]', '["draws attention to"]', '["uppmärksammar"]', '["lenkt Aufmerksamkeit"]', 'advanced', false, 142),
(5, 'Bu yöntem önceki yaklaşımın **aksine** daha verimli.', '**In contrast to** the previous approach, this method is more efficient.', '**I kontrast till** den tidigare metoden är det här effektivare.', '**Im Gegensatz zum** vorherigen Ansatz ist diese Methode effizienter.', '["aksine"]', '["in contrast to"]', '["i kontrast till"]', '["im Gegensatz zu"]', 'advanced', false, 143),
(5, 'Proje gecikmesi **yüzünden** bütçe aşıldı.', '**Due to** the project delay, the budget was exceeded.', '**På grund av** projektförseningen överskreds budgeten.', '**Aufgrund** der Projektverzögerung wurde das Budget überschritten.', '["yüzünden"]', '["due to"]', '["på grund av"]', '["aufgrund"]', 'advanced', false, 144),
(5, 'Yüksek maliyetler yatırımın düşmesine **yol açtı**.', 'The high costs **led to** a drop in investment.', 'De höga kostnaderna **ledde till** en minskning av investeringarna.', 'Die hohen Kosten **führten zu** einem Rückgang der Investitionen.', '["yol açtı"]', '["led to"]', '["ledde till"]', '["führten zu"]', 'advanced', false, 145),
(5, 'Uzun süreli alan araştırması **yürüttüler**.', 'They **carried out** extensive field research.', 'De **genomförde** omfattande fältforskning.', 'Sie haben umfangreiche Feldforschung **durchgeführt**.', '["yürüttüler"]', '["carried out"]', '["genomförde"]', '["durchgeführt"]', 'advanced', false, 146),
(5, 'Uzmanlar nihayet bir **sonuca vardı**.', 'The experts finally **came to a conclusion**.', 'Experterna **nådde slutligen en slutsats**.', 'Die Experten **kamen schließlich zu einem Schluss**.', '["sonuca vardı"]', '["came to a conclusion"]', '["nådde en slutsats"]', '["kamen zu einem Schluss"]', 'advanced', false, 147),
(5, 'Bu fenomen **büyük ölçüde** ekonomik faktörlerle açıklanıyor.', 'This phenomenon is explained **to a large extent** by economic factors.', 'Det här fenomenet förklaras **till stor del** av ekonomiska faktorer.', 'Dieses Phänomen wird **weitgehend** durch wirtschaftliche Faktoren erklärt.', '["büyük ölçüde"]', '["to a large extent"]', '["till stor del"]', '["weitgehend"]', 'advanced', false, 148),
(5, 'Araştırma ve öğretim **aynı anda** yürütülüyor.', 'Research and teaching are conducted **at the same time**.', 'Forskning och undervisning bedrivs **samtidigt**.', 'Forschung und Lehre werden **gleichzeitig** durchgeführt.', '["aynı anda"]', '["at the same time"]', '["samtidigt"]', '["gleichzeitig"]', 'advanced', false, 149),
(5, 'Yeni bir teori **öne sürdüler**.', 'They **put forward** a new theory.', 'De **lade fram** en ny teori.', 'Sie haben eine neue Theorie **vorgelegt**.', '["öne sürdüler"]', '["put forward"]', '["lade fram"]', '["vorgelegt"]', 'advanced', false, 150);

